-- ============================================================================
--  Stage 1 migration, file 4 of 6: STAGING LOAD  (build-order step 5)
--  Generated verbatim from Dan's six exported CSV tabs. Every column is text;
--  the transform (05) casts and validates. Run AFTER 03_functions.sql.
--  Re-runnable: drops and recreates the staging schema each time.
-- ============================================================================
drop schema if exists staging cascade;
create schema staging;

create table staging.reference_lists (category text, top_level_prefix text, description text);

create table staging.item_dictionary (category text, suggested_name text, prefix text, groups text);

create table staging.master_task_matrix (task_id text, target text, name text, category text, instruction text, valid_months text, frequency_days text, suppress_if_raining text, suppress_if_temp_below text, requires_wind_above text, estimated_minutes text);

create table staging.user_profile (asset_id text, category text, friendly_name text, is_active text);

create table staging.task_log (log_id text, task_id text, date_completed text, notes text);

create table staging.hidden_tasks (task_id text, date_hidden text);
